// Initialise loop state. Replace the payload with whatever Trigger emits.
return [{
  json: {
    payload: $input.first()?.json ?? {},
    attempt: 0,
    maxAttempts: 3,
    backoffMs: [2000, 4000, 8000],
    correlationId: `tpl-retry-${Date.now()}-${Math.floor(Math.random() * 1e6)}`
  }
}];

// Increment attempt counter. Out: { proceed: true|false, waitMs }
const s = $input.first().json;
const nextAttempt = (s.attempt ?? 0) + 1;
if (nextAttempt > s.maxAttempts) {
  return [{ json: { ...s, attempt: nextAttempt, exhausted: true } }];
}
return [{ json: { ...s, attempt: nextAttempt, waitMs: s.backoffMs[nextAttempt - 1] } }];

// Replace this Function with your real dead-letter sink (Slack / email / queue).
return [{
  json: {
    deadLetter: true,
    reason: 'max retries exhausted',
    correlationId: $json.correlationId,
    finalAttempt: $json.attempt,
    snapshot: $json.payload
  }
}];
